def ensure_player(uid):
    if "players" not in _data:
        _data["players"] = {}

    if uid not in _data["players"]:
        _data["players"][uid] = {
            "coins": 0,
            "exp": 0,
            "sd": 0
        }

def add_reward(uid, coins=0, exp=0, sd=0):
    ensure_player(uid)

    _data["players"][uid]["coins"] += coins
    _data["players"][uid]["exp"] += exp
    _data["players"][uid]["sd"] += sd

    save_data(_data)

def save_data(data):
    with open(DATA_FILE, "w") as f:
        json.dump(data, f, indent=2)

